 1	@use '../logs/ansi-log-colors' as *;
 2	
 3	.odc-pipeline-run-logs {
 4	  display: flex;
 5	  flex: 1;
 6	  width: 100%;
 7	  position: absolute;
 8	  top: 0;
 9	  bottom: 0;
10	  overflow: hidden;
11	
12	  .pf-v5-c-log-viewer__text {
13	    white-space: pre;
14	  }
15	
16	  @include ansi-log-colors;
17	
18	  &__nav {
19	    padding-top: 0;
20	    list-style-type: none;
21	  }
22	  &__nav .co-icon-and-text {
23	    position: relative;
24	    top: 0.35em;
25	  }
26	  &__namespan {
27	    margin-left: var(--pf-t--global--spacer--200);
28	    white-space: nowrap;
29	    overflow: hidden;
30	    text-overflow: ellipsis;
31	  }
32	  &__log {
33	    height: 100%;
34	    padding-top: var(--pf-t--global--spacer--300);
35	  }
36	  &__logtext {
37	    position: relative;
38	    background: var(
39	      --pf-t--color--gray--100
40	    ); // pod log background color
41	    color: var(--pf-t--global--palette--black-100);
42	    height: 100%;
43	    padding: var(--pf-t--global--spacer--200) var(--pf-t--global--spacer--md);
44	  }
45	  &__logsnippet {
46	    margin-top: var(--pf-t--global--spacer--200);
47	  }
48	  &__tasklist {
49	    max-width: 30%;
50	    min-width: 208px;
51	    margin-top: var(--pf-t--global--spacer--400);
52	    overflow-y: auto;
53	  }
54	  &__container {
55	    flex: 1;
56	  }
57	  &__container .co-m-pane__body {
58	    padding: 0px;
59	  }
60	}
61	
62	.odc-pipeline-run-logs-main-div {
63	  position: relative;
64	  height: 100%;
65	}

