  1	import { TektonResourceLabel } from '../../../consts';
  2	import { ComputedStatus, TaskRunKind } from '../../../types';
  3	import { taskRunStatus } from '../../utils/pipeline-utils';
  4	
  5	jest.mock('../../utils/pipeline-utils', () => ({
  6	  taskRunStatus: jest.fn(),
  7	}));
  8	
  9	class PipelineRunLogsTest {
 10	  getActiveTaskRun = (taskRuns: TaskRunKind[], activeTask: string): string => {
 11	    const activeTaskRun = activeTask
 12	      ? taskRuns.find(
 13	          (taskRun) =>
 14	            taskRun.metadata?.labels?.[TektonResourceLabel.pipelineTask] ===
 15	            activeTask,
 16	        )
 17	      : taskRuns.find(
 18	          (taskRun) => taskRunStatus(taskRun) === ComputedStatus.Failed,
 19	        ) || taskRuns[taskRuns.length - 1];
 20	
 21	    return activeTaskRun?.metadata.name;
 22	  };
 23	}
 24	
 25	describe('PipelineRunLogs - getActiveTaskRun', () => {
 26	  const mockTaskRuns: TaskRunKind[] = [
 27	    {
 28	      kind: 'TaskRun',
 29	      apiVersion: 'tekton.dev/v1',
 30	      metadata: {
 31	        name: 'pipeline-test-tkn-abc',
 32	        namespace: 'test-ns',
 33	        labels: {
 34	          [TektonResourceLabel.pipelineTask]: 'tkn',
 35	        },
 36	      },
 37	      spec: {},
 38	      status: {},
 39	    } as TaskRunKind,
 40	    {
 41	      kind: 'TaskRun',
 42	      apiVersion: 'tekton.dev/v1',
 43	      metadata: {
 44	        name: 'pipeline-test-kn-def',
 45	        namespace: 'test-ns',
 46	        labels: {
 47	          [TektonResourceLabel.pipelineTask]: 'kn',
 48	        },
 49	      },
 50	      spec: {},
 51	      status: {},
 52	    } as TaskRunKind,
 53	    {
 54	      kind: 'TaskRun',
 55	      apiVersion: 'tekton.dev/v1',
 56	      metadata: {
 57	        name: 'pipeline-test-kn-1hr-ghi',
 58	        namespace: 'test-ns',
 59	        labels: {
 60	          [TektonResourceLabel.pipelineTask]: 'kn-1hr',
 61	        },
 62	      },
 63	      spec: {},
 64	      status: {},
 65	    } as TaskRunKind,
 66	  ];
 67	
 68	  let instance: PipelineRunLogsTest;
 69	
 70	  beforeEach(() => {
 71	    instance = new PipelineRunLogsTest();
 72	    jest.clearAllMocks();
 73	  });
 74	
 75	  it('should return exact match for activeTask "kn" and not match "tkn" containing "kn"', () => {
 76	    const result = instance.getActiveTaskRun(mockTaskRuns, 'kn');
 77	    expect(result).toBe('pipeline-test-kn-def');
 78	    // Ensure it doesn't return tkn which contains 'kn'
 79	    expect(result).not.toBe('pipeline-test-tkn-abc');
 80	  });
 81	
 82	  it('should return exact match for activeTask "tkn" and not partially match other tasks', () => {
 83	    const result = instance.getActiveTaskRun(mockTaskRuns, 'tkn');
 84	    expect(result).toBe('pipeline-test-tkn-abc');
 85	    // Ensure it doesn't match kn or kn-1hr
 86	    expect(result).not.toBe('pipeline-test-kn-def');
 87	    expect(result).not.toBe('pipeline-test-kn-1hr-ghi');
 88	  });
 89	
 90	  it('should return the failed task when no activeTask is provided', () => {
 91	    const failedTaskRun: TaskRunKind = {
 92	      kind: 'TaskRun',
 93	      apiVersion: 'tekton.dev/v1',
 94	      metadata: {
 95	        name: 'pipeline-test-failed-task',
 96	        namespace: 'test-ns',
 97	        labels: {
 98	          [TektonResourceLabel.pipelineTask]: 'failed-task',
 99	        },
100	      },
101	      spec: {},
102	      status: {},
103	    } as TaskRunKind;
104	
105	    const taskRunsWithFailed = [...mockTaskRuns, failedTaskRun];
106	
107	    (taskRunStatus as jest.Mock).mockImplementation((taskRun: TaskRunKind) => {
108	      if (taskRun.metadata.name === 'pipeline-test-failed-task') {
109	        return ComputedStatus.Failed;
110	      }
111	      return ComputedStatus.Succeeded;
112	    });
113	
114	    const result = instance.getActiveTaskRun(taskRunsWithFailed, '');
115	    expect(result).toBe('pipeline-test-failed-task');
116	  });
117	});

